/**
 * Packing Slip Item Sort — Grouped by SKU Type
 *
 * Sorts items on packing slips so that:
 *   1. Items with '-Micro' in SKU appear first (together, name-sorted)
 *   2. Items with '-Tip' in SKU appear next (together, name-sorted)
 *   3. Everything else appears last (name-sorted)
 *
 * Replaces the previous two snippets ("Filter Micro Wefts..." and
 * "Filter Tips...") which fought each other on the same filter hook.
 *
 * Hook: admin_only (WPCode "Admin Only" location)
 */

add_filter( 'wpo_wcpdf_order_items_data', function ( $items, $order, $document_type ) {
    if ( $document_type !== 'packing-slip' ) {
        return $items;
    }

    uasort( $items, function ( $a, $b ) {
        $a_sku = (string) ( $a['sku'] ?? '' );
        $b_sku = (string) ( $b['sku'] ?? '' );

        // Group rank: 0 = Micro, 1 = Tip, 2 = everything else
        $rank = function ( $sku ) {
            if ( str_contains( $sku, '-Micro' ) ) return 0;
            if ( str_contains( $sku, '-Tip' ) )   return 1;
            return 2;
        };

        $ra = $rank( $a_sku );
        $rb = $rank( $b_sku );

        if ( $ra !== $rb ) {
            return $ra - $rb;
        }

        // Within the same group, sort by name
        return strnatcasecmp( (string) ( $a['name'] ?? '' ), (string) ( $b['name'] ?? '' ) );
    } );

    return $items;
}, 999, 3 );

