/**
 * Inventory Planner
 *
 * Shows reorder recommendations per product variation based on
 * 30-day sales velocity and a 150-day stock-cover target.
 *
 * Rewrite notes vs. the previous version:
 *   - Escapes all output (fixes XSS via supplier/variation names)
 *   - Bulk-loads 30-day sales with ONE aggregate query instead of
 *     one per variation (was ~N queries on a site with N variations)
 *   - Bulk-loads on-order qty with ONE aggregate query
 *   - Bulk-loads supplier terms in a single taxonomy query
 *   - Filters by supplier at the DB level when a supplier is selected
 *   - Uses transient cache (5 min) so repeat loads are instant
 *   - Replaces inline sort script with a single robust sorter
 */

const FT_INVENTORY_COVER_DAYS   = 150;
const FT_INVENTORY_WINDOW_DAYS  = 30;
const FT_INVENTORY_CACHE_TTL    = 5 * MINUTE_IN_SECONDS;

