/**
 * Build the report with bulk queries (no N+1).
 */
function ft_build_inventory_report( $selected_supplier = 0 ) {
    global $wpdb;

    // 1) One query: every published variation + its stock.
    $supplier_join = '';
    $supplier_where = '';
    if ( $selected_supplier ) {
        // Filter at the DB level by supplier taxonomy on the PARENT product.
        $supplier_join = $wpdb->prepare(
            "INNER JOIN {$wpdb->term_relationships} tr ON tr.object_id = p.post_parent
             INNER JOIN {$wpdb->term_taxonomy} tt ON tt.term_taxonomy_id = tr.term_taxonomy_id
               AND tt.taxonomy = 'atum_supplier'
               AND tt.term_id = %d",
            $selected_supplier
        );
    }

    $variations = $wpdb->get_results( "
        SELECT p.ID AS variation_id,
               p.post_parent AS product_id,
               pm_stock.meta_value AS stock_quantity
        FROM {$wpdb->posts} p
        LEFT JOIN {$wpdb->postmeta} pm_stock
               ON pm_stock.post_id = p.ID AND pm_stock.meta_key = '_stock'
        {$supplier_join}
        WHERE p.post_type = 'product_variation'
          AND p.post_status = 'publish'
    " );

    if ( empty( $variations ) ) {
        return [];
    }

    $variation_ids = array_map( 'intval', wp_list_pluck( $variations, 'variation_id' ) );
    $product_ids   = array_unique( array_map( 'intval', wp_list_pluck( $variations, 'product_id' ) ) );

    // 2) ONE aggregate query for 30-day sales, grouped by variation.
    $sales_map = ft_bulk_sales_last_30_days( $variation_ids );

    // 3) ONE aggregate query for ATUM on-order quantities.
    $on_order_map = ft_bulk_on_order_quantities( $variation_ids );

    // 4) ONE query for supplier term per product (via wp_get_object_terms bulk).
    $supplier_map = ft_bulk_supplier_names( $product_ids );

    // 5) Build rows.
    $report = [];
    foreach ( $variations as $v ) {
        $vid          = (int) $v->variation_id;
        $stock        = (int) $v->stock_quantity;
        $sales        = (int) ( $sales_map[ $vid ] ?? 0 );
        $on_order     = (int) ( $on_order_map[ $vid ] ?? 0 );
        $daily_sales  = $sales / FT_INVENTORY_WINDOW_DAYS;
        $required     = (int) ceil( $daily_sales * FT_INVENTORY_COVER_DAYS );
        $to_order     = max( $required - ( $stock + $on_order ), 0 );

        $product = wc_get_product( $vid );
        $name    = $product ? $product->get_formatted_name() : sprintf( '(#%d)', $vid );

        $report[] = [
            'variation_id'      => $vid,
            'variation_name'    => wp_strip_all_tags( $name ),
            'stock'             => $stock,
            'sales_30d'         => $sales,
            'on_order'          => $on_order,
            'recommended_order' => $to_order,
            'supplier'          => $supplier_map[ (int) $v->product_id ] ?? '',
        ];
    }

    return $report;
}

/**
 * Bulk 30-day sales, grouped by variation_id.
 *
 * @param int[] $variation_ids
 * @return array<int,int>  variation_id => qty
 */
function ft_bulk_sales_last_30_days( array $variation_ids ) {
    global $wpdb;
    if ( empty( $variation_ids ) ) return [];

    $placeholders = implode( ',', array_fill( 0, count( $variation_ids ), '%d' ) );
    $days         = FT_INVENTORY_WINDOW_DAYS;

    $sql = $wpdb->prepare( "
        SELECT CAST(meta_var.meta_value AS UNSIGNED) AS variation_id,
               SUM(CAST(meta_qty.meta_value AS UNSIGNED)) AS qty
        FROM {$wpdb->prefix}woocommerce_order_itemmeta meta_qty
        INNER JOIN {$wpdb->prefix}woocommerce_order_items items
                ON meta_qty.order_item_id = items.order_item_id
        INNER JOIN {$wpdb->prefix}woocommerce_order_itemmeta meta_var
                ON meta_var.order_item_id = items.order_item_id
        INNER JOIN {$wpdb->posts} orders
                ON items.order_id = orders.ID
        WHERE meta_qty.meta_key = '_qty'
          AND meta_var.meta_key = '_variation_id'
          AND meta_var.meta_value IN ({$placeholders})
          AND orders.post_type = 'shop_order'
          AND orders.post_status IN ('wc-completed', 'wc-processing')
          AND orders.post_date >= DATE_SUB(NOW(), INTERVAL %d DAY)
        GROUP BY meta_var.meta_value
    ", array_merge( $variation_ids, [ $days ] ) );

    $rows = $wpdb->get_results( $sql );
    $map  = [];
    foreach ( $rows as $r ) {
        $map[ (int) $r->variation_id ] = (int) $r->qty;
    }
    return $map;
}

/**
 * Bulk ATUM on-order quantities, grouped by variation/product id.
 */
function ft_bulk_on_order_quantities( array $variation_ids ) {
    global $wpdb;
    if ( empty( $variation_ids ) ) return [];

    $table = $wpdb->prefix . 'atum_order_items';
    if ( ! $wpdb->get_var( $wpdb->prepare( "SHOW TABLES LIKE %s", $table ) ) ) {
        return [];
    }

    $placeholders = implode( ',', array_fill( 0, count( $variation_ids ), '%d' ) );

    $sql = $wpdb->prepare( "
        SELECT CAST(m_pid.meta_value AS UNSIGNED) AS variation_id,
               SUM(CAST(m_qty.meta_value AS UNSIGNED)) AS qty_on_order
        FROM {$wpdb->prefix}atum_order_items oi
        INNER JOIN {$wpdb->posts} p ON oi.order_id = p.ID
        INNER JOIN {$wpdb->prefix}atum_order_itemmeta m_pid
                ON m_pid.order_item_id = oi.order_item_id
               AND m_pid.meta_key IN ('_variation_id', '_product_id')
        INNER JOIN {$wpdb->prefix}atum_order_itemmeta m_qty
                ON m_qty.order_item_id = oi.order_item_id
               AND m_qty.meta_key = '_qty'
        WHERE p.post_status = 'atum_ordered'
          AND m_pid.meta_value IN ({$placeholders})
        GROUP BY m_pid.meta_value
    ", $variation_ids );

    $rows = $wpdb->get_results( $sql );
    $map  = [];
    foreach ( $rows as $r ) {
        $map[ (int) $r->variation_id ] = (int) $r->qty_on_order;
    }
    return $map;
}

/**
 * Bulk supplier names keyed by product ID (uses one get_terms per product
 * batch by leveraging WP's object term cache).
 */
function ft_bulk_supplier_names( array $product_ids ) {
    if ( empty( $product_ids ) ) return [];
    // Prime the object-term cache in one go.
    update_object_term_cache( $product_ids, 'product' );

    $map = [];
    foreach ( $product_ids as $pid ) {
        $terms = wp_get_object_terms( $pid, 'atum_supplier', [ 'fields' => 'names' ] );
        if ( ! is_wp_error( $terms ) && ! empty( $terms ) ) {
            $map[ $pid ] = $terms[0];
        }
    }
    return $map;
}

