function atum_find_supplier_id_for_product($product_id, $parent_id = 0) {
	global $wpdb;

	$meta_keys = ['_supplier', '_atum_supplier', 'supplier_id', 'atum_supplier'];
	foreach ($meta_keys as $key) {
		$val = get_post_meta($product_id, $key, true);
		if (!empty($val)) return $val;
	}

	if ($parent_id && $parent_id !== $product_id) {
		foreach ($meta_keys as $key) {
			$val = get_post_meta($parent_id, $key, true);
			if (!empty($val)) return $val;
		}
	}

	$table = $wpdb->prefix . 'atum_product_data';
	if ($wpdb->get_var($wpdb->prepare("SHOW TABLES LIKE %s", $table))) {
		$supplier_id = $wpdb->get_var($wpdb->prepare(
			"SELECT supplier_id FROM {$table} WHERE product_id = %d LIMIT 1",
			$product_id
		));
		if (!empty($supplier_id)) return $supplier_id;
	}

	return '';
}

function atum_find_supplier_sku_for_product($product_id, $parent_id = 0) {
	$supplier_sku = get_post_meta($product_id, '_supplier_sku', true);
	if (empty($supplier_sku) && $parent_id) {
		$supplier_sku = get_post_meta($parent_id, '_supplier_sku', true);
	}
	return $supplier_sku ?: '—';
}

function sales_last_x_days_page() {
	$days = isset($_GET['days']) ? absint($_GET['days']) : 60;
	$supplier_filter = isset($_GET['supplier']) ? sanitize_text_field($_GET['supplier']) : '';

	echo '<div class="wrap"><h1>Sales in Last ' . esc_html($days) . ' Days</h1>';

	$suppliers = get_posts([
		'post_type' => 'atum_supplier',
		'posts_per_page' => -1,
		'post_status' => 'publish',
		'orderby' => 'title',
		'order' => 'ASC',
	]);

	echo '<form method="get" style="margin-bottom: 20px;">
		<input type="hidden" name="page" value="sales-last-x-days" />
		<label>Days: <input type="number" name="days" value="' . esc_attr($days) . '" min="1" max="365" /></label> &nbsp;
		<label>Supplier:
			<select name="supplier">
				<option value="">All Suppliers</option>';
	foreach ($suppliers as $supplier) {
		$selected = selected($supplier_filter, $supplier->ID, false);
		echo '<option value="' . esc_attr($supplier->ID) . '" ' . $selected . '>' . esc_html($supplier->post_title) . '</option>';
	}
	echo '</select></label> &nbsp;
		<button type="submit" class="button button-primary">Filter</button>
	</form>';

	if (isset($_GET['export']) && $_GET['export'] === 'csv') {
		sales_last_x_days_export_csv($days, $supplier_filter);
		exit;
	}

	$start_date = gmdate('Y-m-d', strtotime("-{$days} days"));
	$order_ids = wc_get_orders([
		'status' => ['wc-completed', 'wc-processing'],
		'date_created' => '>' . $start_date,
		'limit' => -1,
		'return' => 'ids',
	]);

	if (empty($order_ids)) {
		echo '<div class="notice notice-info"><p>No orders found.</p></div></div>';
		return;
	}

	$sales = [];

	foreach ($order_ids as $order_id) {
		$order = wc_get_order($order_id);
		foreach ($order->get_items() as $item) {
			$product = $item->get_product();
			if (!$product) continue;

			$product_id  = $product->get_id();
			$parent_id   = $product->is_type('variation') ? $product->get_parent_id() : 0;
			$name        = $product->get_name();
			$sku         = $product->get_sku() ?: '—';
			$qty         = $item->get_quantity();
			$supplier_id = atum_find_supplier_id_for_product($product_id, $parent_id);
			$supplier_sku = atum_find_supplier_sku_for_product($product_id, $parent_id);

			if ($supplier_filter && $supplier_id != $supplier_filter) continue;

			$key = $product_id;
			if (isset($sales[$key])) {
				$sales[$key]['qty'] += $qty;
			} else {
				$sales[$key] = [
					'name'         => $name,
					'sku'          => $sku,
					'qty'          => $qty,
					'product_id'   => $product_id,
					'parent_id'    => $parent_id,
					'supplier_id'  => $supplier_id,
					'supplier_sku' => $supplier_sku,
				];
			}
		}
	}

	if (empty($sales)) {
		echo '<div class="notice notice-info"><p>No matching products found.</p></div></div>';
		return;
	}

	$export_url = add_query_arg([
		'page'     => 'sales-last-x-days',
		'days'     => $days,
		'supplier' => $supplier_filter,
		'export'   => 'csv',
	], admin_url('admin.php'));

	echo '<p><a href="' . esc_url($export_url) . '" class="button">Export CSV</a></p>';

	echo '<table class="widefat striped sortable-table"><thead>
	<tr>
		<th>Product</th>
		<th>Variation</th>
		<th>SKU</th>
		<th>Supplier</th>
		<th>Supplier SKU</th>
		<th>Current Stock</th>
		<th>Units Sold</th>
	</tr></thead><tbody>';

	foreach ($sales as $sale) {
		$product = wc_get_product($sale['product_id']);
		if (!$product) continue;

		$parent_name = $sale['parent_id'] ? get_the_title($sale['parent_id']) : '';
		$variation_name = '—';
		if ($sale['parent_id'] && $product->is_type('variation')) {
			$attrs = [];
			foreach ($product->get_variation_attributes() as $val) {
				$attrs[] = $val;
			}
			$variation_name = implode(', ', array_filter($attrs));
		}

		$current_stock = $product->get_stock_quantity();
		if ($current_stock === null) $current_stock = '—';

		$supplier_name = '—';
		if (!empty($sale['supplier_id'])) {
			$supplier_post = get_post($sale['supplier_id']);
			if ($supplier_post) $supplier_name = $supplier_post->post_title;
		}

		printf(
			'<tr>
				<td>%s</td>
				<td>%s</td>
				<td>%s</td>
				<td>%s</td>
				<td>%s</td>
				<td>%s</td>
				<td>%d</td>
			</tr>',
			esc_html($parent_name ?: $sale['name']),
			esc_html($variation_name),
			esc_html($sale['sku']),
			esc_html($supplier_name),
			esc_html($sale['supplier_sku']),
			esc_html($current_stock),
			(int)$sale['qty']
		);
	}

	echo '</tbody></table></div>';

	echo '<script>
	document.addEventListener("DOMContentLoaded", function() {
		const table = document.querySelector(".sortable-table");
		if (!table) return;
		const headers = table.querySelectorAll("th");
		headers.forEach((header, i) => {
			header.style.cursor = "pointer";
			header.addEventListener("click", () => {
				const rows = Array.from(table.querySelectorAll("tbody tr"));
				const asc = !header.classList.contains("asc");
				headers.forEach(h => h.classList.remove("asc", "desc"));
				header.classList.add(asc ? "asc" : "desc");

				rows.sort((a, b) => {
					let A = a.children[i].innerText.trim().toLowerCase();
					let B = b.children[i].innerText.trim().toLowerCase();
					if (!isNaN(A) && !isNaN(B)) return asc ? A - B : B - A;
					return asc ? A.localeCompare(B) : B.localeCompare(A);
				});

				const tbody = table.querySelector("tbody");
				tbody.innerHTML = "";
				rows.forEach(r => tbody.appendChild(r));
			});
		});
	});
	</script>';
}

function sales_last_x_days_export_csv($days, $supplier_filter = '') {
	$filename = 'sales_last_' . $days . '_days_' . date('Ymd_His') . '.csv';
	header('Content-Type: text/csv');
	header('Content-Disposition: attachment; filename="' . $filename . '"');
	$output = fopen('php://output', 'w');
	fputcsv($output, ['Product', 'Variation', 'SKU', 'Supplier', 'Supplier SKU', 'Current Stock', 'Units Sold']);

	$start_date = gmdate('Y-m-d', strtotime("-{$days} days"));
	$order_ids = wc_get_orders([
		'status' => ['wc-completed', 'wc-processing'],
		'date_created' => '>' . $start_date,
		'limit' => -1,
		'return' => 'ids',
	]);

	$sales = [];
	foreach ($order_ids as $order_id) {
		$order = wc_get_order($order_id);
		foreach ($order->get_items() as $item) {
			$product = $item->get_product();
			if (!$product) continue;

			$product_id = $product->get_id();
			$parent_id = $product->is_type('variation') ? $product->get_parent_id() : 0;
			$name = $product->get_name();
			$sku = $product->get_sku() ?: '—';
			$qty = $item->get_quantity();
			$supplier_id = atum_find_supplier_id_for_product($product_id, $parent_id);
			$supplier_sku = atum_find_supplier_sku_for_product($product_id, $parent_id);

			if ($supplier_filter && $supplier_id != $supplier_filter) continue;

			$key = $product_id;
			if (isset($sales[$key])) $sales[$key]['qty'] += $qty;
			else $sales[$key] = [
				'name' => $name,
				'sku' => $sku,
				'qty' => $qty,
				'product_id' => $product_id,
				'parent_id' => $parent_id,
				'supplier_id' => $supplier_id,
				'supplier_sku' => $supplier_sku,
			];
		}
	}

	foreach ($sales as $sale) {
		$product = wc_get_product($sale['product_id']);
		if (!$product) continue;

		$parent_name = $sale['parent_id'] ? get_the_title($sale['parent_id']) : '';
		$variation_name = '—';
		if ($sale['parent_id'] && $product->is_type('variation')) {
			$attrs = [];
			foreach ($product->get_variation_attributes() as $val) {
				$attrs[] = $val;
			}
			$variation_name = implode(', ', array_filter($attrs));
		}

		$current_stock = $product->get_stock_quantity();
		if ($current_stock === null) $current_stock = '—';

		$supplier_name = '—';
		if (!empty($sale['supplier_id'])) {
			$supplier_post = get_post($sale['supplier_id']);
			if ($supplier_post) $supplier_name = $supplier_post->post_title;
		}

		fputcsv($output, [
			$parent_name ?: $sale['name'],
			$variation_name,
			$sale['sku'],
			$supplier_name,
			$sale['supplier_sku'],
			$current_stock,
			(int)$sale['qty'],
		]);
	}

	fclose($output);
	exit;
}

jQuery(function ($) {

  $(document).on('click', '.qty-btn.plus', function () {
    const $qty = $(this).siblings('input.qty');
    const max = parseFloat($qty.attr('max')) || Infinity;
    const step = parseFloat($qty.attr('step')) || 1;
    let val = parseFloat($qty.val()) || 0;

    if (val < max) {
      $qty.val(val + step).change();
    }
  });

  $(document).on('click', '.qty-btn.minus', function () {
    const $qty = $(this).siblings('input.qty');
    const min = parseFloat($qty.attr('min')) || 0;
    const step = parseFloat($qty.attr('step')) || 1;
    let val = parseFloat($qty.val()) || 0;

    if (val > min) {
      $qty.val(val - step).change();
    }
  });

});

