(function () {
  function init() {
    document.querySelectorAll('.ft-tabs').forEach(function (tabBar) {
      tabBar.addEventListener('click', function (e) {
        var btn = e.target.closest('.ft-tab');
        if (!btn) return;

        var group = tabBar.getAttribute('data-group');
        var tab = btn.getAttribute('data-tab');
        if (!group || !tab) return;

        tabBar.querySelectorAll('.ft-tab').forEach(function (t) {
          t.classList.remove('active');
        });
        btn.classList.add('active');

        document.querySelectorAll('.ft-panel[data-group="' + group + '"]').forEach(function (p) {
          if (p.getAttribute('data-tab') === tab) {
            p.classList.add('active');
          } else {
            p.classList.remove('active');
          }
        });
      });
    });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();

