/* =========================================================
   FT — My Account Auto-Scroll to Tabs
   ---------------------------------------------------------
   Scrolls to the account navigation when a sub-tab page
   loads, so users don't have to scroll past the header.

   Relies on CSS `scroll-margin-top: var(--ft-scroll-offset)`
   on .woocommerce-MyAccount-navigation (set in the My Account
   stylesheet). That's the single source of truth for header
   height — no magic numbers here.
   ========================================================= */

(function () {
  'use strict';

  document.addEventListener('DOMContentLoaded', function () {
    var body = document.body;
    if (!body.classList.contains('woocommerce-account')) return;
    if (!body.classList.contains('logged-in')) return;

    // Only scroll on actual sub-tab pages, not the top-level /my-account/.
    var path = window.location.pathname.replace(/\/+$/, '');
    var isSubTab = /\/my-account\/[^\/]+/.test(path);
    if (!isSubTab) return;

    var nav = document.querySelector('.woocommerce-MyAccount-navigation');
    if (!nav) return;

    // rAF ensures layout has settled (fonts, lazy images above).
    requestAnimationFrame(function () {
      nav.scrollIntoView({ block: 'start', behavior: 'auto' });
    });
  });
})();

