document.addEventListener('DOMContentLoaded', function () {

  /* Only run on shop archive and taxonomy archive pages */
  var b = document.body.classList;
  var isShop = b.contains('post-type-archive-product');
  var isArchive = b.contains('tax-product_tag') || b.contains('tax-product_cat');
  if (!isShop && !isArchive) return;


  /* =========================================================
     BREADCRUMB BAR — Archive pages only
     ---------------------------------------------------------
     Injects a "Shop › Category Name" breadcrumb above the
     product grid on /product-tag/ and /product-category/ pages.
     Pulls the category name from the page <title> and strips
     the site name suffix.
     ========================================================= */

  /* Robust category-name lookup:
     1) The Woo archive <h1> is the most reliable source.
     2) Fallback: derive from the term-SLUG body class.
     3) Last resort: the old <title> parsing. */
  function ftReadCategoryName() {
    var h = document.querySelector('.woocommerce-products-header__title, h1.page-title, h1.entry-title');
    if (h && h.textContent.trim()) return h.textContent.trim();

    var slug = (document.body.className.match(/term-([a-z0-9-]+)/i) || [])[1];
    if (slug) {
      return slug.replace(/-/g, ' ').replace(/\b\w/g, function (c) { return c.toUpperCase(); });
    }

    var rawTitle = document.title || '';
    return rawTitle.split('|')[0].replace(/\s*[–—-]\s*$/, '').trim();
  }

  if (isArchive) {
    (function () {
      /* --- Breadcrumb bar --- */
      var catName = ftReadCategoryName();

      var gridRow = document.querySelector('.x-row-inner');
      if (!gridRow) return;
      var insertTarget = gridRow.closest('.x-row');
      if (!insertTarget) return;

      var bar = document.createElement('div');
      bar.className = 'ft-breadcrumb-bar';
      bar.innerHTML =
        '<a href="/shop/" class="ft-bc-link">Shop</a>' +
        '<span class="ft-bc-sep">\u203A</span>' +
        '<span class="ft-bc-current">' + catName + '</span>';

      insertTarget.parentNode.insertBefore(bar, insertTarget);

      /* --- Auto-activate matching filter tab + panel ---
         Match the current URL path against filter link hrefs
         to find which panel contains a link to this page,
         then activate that tab and open that panel. Also
         highlight the matching link. */

      var path = window.location.pathname.replace(/\/+$/, '');
      var links = document.querySelectorAll('.ft-filter-link');
      var matchedPanel = null;

      for (var i = 0; i < links.length; i++) {
        var linkPath = links[i].getAttribute('href').replace(/\/+$/, '');
        if (linkPath === path) {
          links[i].classList.add('ft-filter-link--active');
          matchedPanel = links[i].closest('.ft-filter-panel');
          break;
        }
      }

      if (matchedPanel) {
        var panelId = matchedPanel.getAttribute('data-panel');
        var tabs = document.querySelectorAll('.ft-filter-tab');
        var panels = document.querySelectorAll('.ft-filter-panel');

        /* Activate the matching tab */
        tabs.forEach(function (t) {
          if (t.getAttribute('data-tab') === panelId) {
            t.classList.add('ft-filter-tab--active');
          }
        });

        /* Insert filter pill below the tab bar */
        var tabBar = document.querySelector('.ft-filter-tabs');
        if (tabBar) {
          var pillWrap = document.createElement('div');
          pillWrap.className = 'ft-filter-pill-wrap';
          var pill = document.createElement('a');
          pill.href = '/shop/';
          pill.className = 'ft-filter-pill';
          pill.setAttribute('aria-label', 'Clear filter — return to shop');
          pill.innerHTML = catName +
            ' <svg viewBox="0 0 15 15" fill="none" xmlns="http://www.w3.org/2000/svg">' +
              '<line x1="5" y1="5" x2="10" y2="10" stroke="currentColor" stroke-width="1.3" stroke-linecap="round"/>' +
              '<line x1="10" y1="5" x2="5" y2="10" stroke="currentColor" stroke-width="1.3" stroke-linecap="round"/>' +
            '</svg>';
          pillWrap.appendChild(pill);
          tabBar.insertAdjacentElement('afterend', pillWrap);
        }

        /* Show the matching panel */
        matchedPanel.classList.add('ft-filter-panel--active');
      }
    })();
  }


  /* =========================================================
     HELPER: Update Pro theme cart count
     ---------------------------------------------------------
     The Pro/X theme cart toggle uses span.x-anchor-text-primary
     inside the cart anchor. WooCommerce fragments don't cover
     this element, so we fetch the cart page and parse the count,
     or more reliably, use the WC cart hash cookie + fragments.
     Simplest: after any add-to-cart, fetch the cart endpoint
     and count items from the returned fragment HTML.
     ========================================================= */

  function updateCartCount() {
    if (typeof jQuery === 'undefined') return;

    jQuery.post('/?wc-ajax=get_refreshed_fragments', function (data) {
      if (!data || !data.fragments) return;

      /* Inject all standard WC fragments */
      jQuery.each(data.fragments, function (key, value) {
        if (jQuery(key).length) {
          jQuery(key).replaceWith(value);
        }
      });

      /* Extract cart count from the widget fragment */
      var widgetHtml = data.fragments['div.widget_shopping_cart_content'];
      if (widgetHtml) {
        var temp = document.createElement('div');
        temp.innerHTML = widgetHtml;
        var items = temp.querySelectorAll('.woocommerce-mini-cart-item');
        var totalQty = 0;

        /* Count total quantity from qty displays, or just count line items */
        items.forEach(function (item) {
          var qtyEl = item.querySelector('.quantity');
          if (qtyEl) {
            var match = qtyEl.textContent.match(/(\d+)/);
            if (match) totalQty += parseInt(match[1], 10);
          } else {
            totalQty += 1;
          }
        });

        /* Update all Pro theme cart count elements */
        document.querySelectorAll('.x-anchor-text-primary').forEach(function (el) {
          /* Only update ones inside cart toggles */
          var anchor = el.closest('.x-anchor-toggle');
          if (anchor) {
            el.textContent = totalQty;
          }
        });
      }
    });
  }

  /* SVG icons */
  var iconOpen =
    '<svg class="ft-qa-icon-open" viewBox="0 0 15 15" fill="none" xmlns="http://www.w3.org/2000/svg">' +
      '<circle cx="7.5" cy="7.5" r="6.5" stroke="#c4a882" stroke-width="1.1"/>' +
      '<line x1="7.5" y1="4.5" x2="7.5" y2="10.5" stroke="#c4a882" stroke-width="1.1" stroke-linecap="round"/>' +
      '<line x1="4.5" y1="7.5" x2="10.5" y2="7.5" stroke="#c4a882" stroke-width="1.1" stroke-linecap="round"/>' +
    '</svg>';

  var iconClose =
    '<svg class="ft-qa-icon-close" viewBox="0 0 15 15" fill="none" xmlns="http://www.w3.org/2000/svg">' +
      '<circle cx="7.5" cy="7.5" r="6.5" stroke="#b5b0a8" stroke-width="1.1"/>' +
      '<line x1="5" y1="5" x2="10" y2="10" stroke="#b5b0a8" stroke-width="1.1" stroke-linecap="round"/>' +
      '<line x1="10" y1="5" x2="5" y2="10" stroke="#b5b0a8" stroke-width="1.1" stroke-linecap="round"/>' +
    '</svg>';

  /* Find every product card */
  var cards = document.querySelectorAll('article.ft-shop');

  cards.forEach(function (card) {
    var formWrap = card.querySelector('.x-wc-add-to-cart-form');
    if (!formWrap) return;

    /* ---- Build the Quick Add trigger ---- */
    var trigger = document.createElement('button');
    trigger.type = 'button';
    trigger.className = 'ft-quick-add-trigger';
    trigger.setAttribute('aria-expanded', 'false');
    trigger.innerHTML = iconOpen + iconClose + '<span class="ft-quick-add-label">Quick Add</span>';

    /* Insert trigger before the form wrapper */
    formWrap.parentNode.insertBefore(trigger, formWrap);

    /* Toggle open/close on click */
    trigger.addEventListener('click', function () {
      var isOpen = card.classList.contains('ft-quick-add-open');

      /* Close any other open cards first */
      document.querySelectorAll('article.ft-shop.ft-quick-add-open').forEach(function (other) {
        if (other !== card) {
          other.classList.remove('ft-quick-add-open');
          var otherTrigger = other.querySelector('.ft-quick-add-trigger');
          if (otherTrigger) {
            otherTrigger.setAttribute('aria-expanded', 'false');
            otherTrigger.querySelector('.ft-quick-add-label').textContent = 'Quick Add';
          }
        }
      });

      /* Toggle current card */
      if (isOpen) {
        card.classList.remove('ft-quick-add-open');
        trigger.setAttribute('aria-expanded', 'false');
        trigger.querySelector('.ft-quick-add-label').textContent = 'Quick Add';
      } else {
        card.classList.add('ft-quick-add-open');
        trigger.setAttribute('aria-expanded', 'true');
        trigger.querySelector('.ft-quick-add-label').textContent = 'Close';
      }
    });
  });

  /* =========================================================
     VARIATION SELECTED / RESET — EVENT DELEGATION VIA JQUERY
     ========================================================= */

  if (typeof jQuery !== 'undefined') {
    jQuery('body.post-type-archive-product, body.tax-product_tag, body.tax-product_cat').on('found_variation', 'form.variations_form', function () {
      var wrap = this.querySelector('.single_variation_wrap');
      if (wrap) wrap.classList.add('ft-variation-selected');
    });

    jQuery('body.post-type-archive-product, body.tax-product_tag, body.tax-product_cat').on('reset_data', 'form.variations_form', function () {
      var wrap = this.querySelector('.single_variation_wrap');
      if (wrap) wrap.classList.remove('ft-variation-selected');
    });
  }

  /* =========================================================
     AJAX ADD TO CART — ALL PRODUCTS (EVENT DELEGATION)
     ---------------------------------------------------------
     Catches all form.cart submits inside .ft-shop cards on the
     archive page and sends them via AJAX instead of a full
     page POST. Handles both variable and simple products.
     ========================================================= */

  document.addEventListener('submit', function (e) {
    var form = e.target;

    /* Only intercept form.cart inside our shop cards */
    if (!form.classList.contains('cart')) return;
    var card = form.closest('article.ft-shop');
    if (!card) return;

    e.preventDefault();

    var isVariable = form.classList.contains('variations_form');
    var submitBtn = form.querySelector('.single_add_to_cart_button');
    var qty = form.querySelector('input.qty');
    var qtyVal = qty ? qty.value : 1;

    /* For variable products, check variation is selected */
    if (isVariable) {
      var variationId = form.querySelector('input.variation_id');
      if (!variationId || !variationId.value || variationId.value === '0') return;
    }

    /* Get product ID from the form */
    var productIdInput = form.querySelector('input[name="product_id"]');
    var addToCartInput = form.querySelector('button[name="add-to-cart"], input[name="add-to-cart"]');
    var productId = productIdInput
      ? productIdInput.value
      : (addToCartInput ? addToCartInput.value : null);

    if (!productId) return;

    /* Build form data */
    var data = new URLSearchParams();
    data.append('product_id', productId);
    data.append('quantity', qtyVal);
    data.append('add-to-cart', productId);

    if (isVariable) {
      data.append('variation_id', form.querySelector('input.variation_id').value);

      /* Include selected attributes */
      form.querySelectorAll('select[name^="attribute_"]').forEach(function (sel) {
        data.append(sel.name, sel.value);
      });
    }

    /* Optimistic feedback — show the user something instantly so the
       500ms+ server round-trip doesn't feel like nothing is happening.
       If the request fails we'll revert below. */
    var originalText = submitBtn.textContent;
    submitBtn.textContent = 'Added \u2713';
    submitBtn.disabled = true;
    submitBtn.style.pointerEvents = 'none';

    fetch(form.action, {
      method: 'POST',
      body: data,
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'X-Requested-With': 'XMLHttpRequest',
        'Accept': 'application/json, text/html'
      }
    })
    .then(function (res) {
      if (!res.ok && !res.redirected) throw new Error('HTTP ' + res.status);

      /* Woo's AJAX add-to-cart response includes the refreshed fragments
         already — use them instead of firing a second request to
         ?wc-ajax=get_refreshed_fragments. Cuts one full WordPress boot
         out of the flow. Response may be JSON or HTML depending on Woo
         version, so try JSON first and fall back silently. */
      return res.clone().json().catch(function () { return null; });
    })
    .then(function (payload) {
      if (payload && payload.fragments && typeof jQuery !== 'undefined') {
        jQuery.each(payload.fragments, function (key, value) {
          if (jQuery(key).length) {
            jQuery(key).replaceWith(value);
          }
        });

        /* Update Pro theme cart count from the widget fragment */
        var widgetHtml = payload.fragments['div.widget_shopping_cart_content'];
        if (widgetHtml) {
          var temp = document.createElement('div');
          temp.innerHTML = widgetHtml;
          var miniItems = temp.querySelectorAll('.woocommerce-mini-cart-item');
          var totalQty = 0;
          miniItems.forEach(function (item) {
            var qtyEl = item.querySelector('.quantity');
            if (qtyEl) {
              var m = qtyEl.textContent.match(/(\d+)/);
              if (m) totalQty += parseInt(m[1], 10);
            } else {
              totalQty += 1;
            }
          });
          document.querySelectorAll('.x-anchor-text-primary').forEach(function (el) {
            if (el.closest('.x-anchor-toggle')) el.textContent = totalQty;
          });
        }

        /* Fire the event that mini-cart drawers and related plugins expect */
        jQuery(document.body).trigger('added_to_cart',
          [payload.fragments, payload.cart_hash, jQuery(submitBtn)]);
      } else {
        /* Response wasn't JSON (older Woo, redirect, etc.) — fall back to
           the old behavior so cart count still updates. One extra round-trip
           but at least it's correct. */
        updateCartCount();
      }

      setTimeout(function () {
        submitBtn.textContent = originalText;
        submitBtn.disabled = false;
        submitBtn.style.pointerEvents = '';
      }, 1200);
    })
    .catch(function () {
      /* Revert optimistic UI on failure */
      submitBtn.textContent = originalText;
      submitBtn.disabled = false;
      submitBtn.style.pointerEvents = '';
    });
  }, true);

});
// ── Simple product price injection ──
(function() {
  var priceCache = {};

  /* Extract the price-injection logic so it can run from either an
     event (the Quick Add click) or the narrow fallback observer below.
     Previously this ran inside a MutationObserver watching the entire
     body with subtree:true + attributes:true, which fired hundreds of
     times per second during normal scrolling. */
  function ftInjectSimplePrice(card) {
    if (card.querySelector('.ft-simple-price')) return;       // already injected

    var trigger = card.querySelector('.ft-quick-add-trigger');
    if (!trigger || trigger.getAttribute('aria-expanded') !== 'true') return;

    var formWrap = card.querySelector('.x-wc-add-to-cart-form');
    if (!formWrap) return;

    var form = formWrap.querySelector('form.cart');

    /* Variable products handle their own price/login display via the
       native WooCommerce variations form — skip them here. */
    if (form && form.querySelector('.variations')) return;

    var isLoggedIn = document.body.classList.contains('logged-in');

    /* Guest branch — for logged-out users.
       B2BKing strips form.cart entirely for guests on simple products
       (unlike variable products, where it keeps the variations form
       and only disables the button). That leaves .x-wc-add-to-cart-form
       as an empty container. Inject the B2BKing-style "Log In to View
       Prices" message directly into that container so guests see the
       same treatment they get on variable products and single product
       pages (via the [ft_single_price] shortcode). */
    if (!isLoggedIn) {
      var guestMarker = document.createElement('div');
      guestMarker.className = 'ft-simple-price ft-simple-price--guest';
      guestMarker.innerHTML =
        '<span class="b2bking_hidden_price_text">' +
          '<a href="/my-account/">Log In to View Prices</a>' +
        '</span>';
      formWrap.appendChild(guestMarker);
      return;
    }

    /* Logged-in branch — original behavior: inject price above the
       qty selector, fetched from the Store API and cached. Requires
       form.cart and the add-to-cart button to be present. */
    if (!form) return;

    var btn = form.querySelector('button[name="add-to-cart"]');
    if (!btn) return;
    var productId = btn.value;
    if (!productId) return;

    var marker = document.createElement('div');
    marker.className = 'ft-simple-price';
    marker.textContent = '';
    var qty = form.querySelector('.quantity');
    if (qty) {
      qty.parentNode.insertBefore(marker, qty);
    } else {
      form.insertBefore(marker, btn);
    }

    if (priceCache[productId]) {
      marker.textContent = priceCache[productId];
      return;
    }

    fetch('/wp-json/wc/store/v1/products/' + productId)
      .then(function(r) { return r.json(); })
      .then(function(data) {
        var raw = data.prices && data.prices.price;
        if (raw) {
          var dollars = (parseInt(raw, 10) / 100).toFixed(2);
          var display = '$' + dollars;
          priceCache[productId] = display;
          marker.textContent = display;
        }
      })
      .catch(function() {});
  }

  /* Primary trigger: run right after a Quick Add button is clicked.
     Uses the capture phase so it runs before any user handlers;
     uses a microtask delay so the 'ft-quick-add-open' class has
     already been set by the toggle handler. */
  document.addEventListener('click', function(e) {
    var trigger = e.target.closest('.ft-quick-add-trigger');
    if (!trigger) return;
    var card = trigger.closest('article.ft-shop');
    if (!card) return;
    Promise.resolve().then(function() { ftInjectSimplePrice(card); });
  });

  /* Narrow fallback: only fires if new .ft-shop cards are injected
     later (AJAX filter, infinite scroll, etc.). Watches for new
     nodes only — no attribute watching, no deep subtree traversal
     beyond what's needed to detect added cards. */
  function ftStartFallbackObserver() {
    var grid = document.querySelector('.x-row-inner') || document.body;
    var observer = new MutationObserver(function(mutations) {
      for (var i = 0; i < mutations.length; i++) {
        var added = mutations[i].addedNodes;
        for (var j = 0; j < added.length; j++) {
          var node = added[j];
          if (node.nodeType !== 1) continue;
          if (node.matches && node.matches('article.ft-shop')) {
            ftInjectSimplePrice(node);
          } else if (node.querySelectorAll) {
            node.querySelectorAll('article.ft-shop').forEach(ftInjectSimplePrice);
          }
        }
      }
    });
    observer.observe(grid, { childList: true, subtree: true });
  }

  if (document.body) {
    ftStartFallbackObserver();
  } else {
    document.addEventListener('DOMContentLoaded', ftStartFallbackObserver);
  }
})();

/* ═══════════════════════════════════════
   Frame & Thread — Shop Filter & Category Cards
   Snippet: Shop Filter CSS
   Scope: Frontend only
═══════════════════════════════════════ */

/* ── CONTAINER ── */
.ft-shop-container {
  max-width: 1400px;
  margin: 0 auto;
  padding: 0 2rem;
}

/* ── CATEGORY CARDS ── */
.ft-category-cards {
  padding: 3rem 0 2.5rem;
}

.ft-category-cards__heading {
  font-family: 'Cormorant Garamond', serif;
  font-style: italic;
  font-weight: 300;
  font-size: 1.15rem;
  letter-spacing: 0.08em;
  color: #999;
  text-align: center;
  margin-bottom: 2rem;
}

.ft-category-cards__grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 1.25rem;
}

.ft-category-card {
  position: relative;
  display: block;
  text-decoration: none;
  color: #1a1a1a;
  overflow: hidden;
  aspect-ratio: 3 / 4;
  background: #f5f1ed;
  cursor: pointer;
}

.ft-category-card__image {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.8s cubic-bezier(0.25, 0.1, 0.25, 1);
}

.ft-category-card:hover .ft-category-card__image {
  transform: scale(1.04);
}

.ft-category-card__overlay {
  position: absolute;
  inset: 0;
  background: linear-gradient(to top, rgba(26, 26, 26, 0.55) 0%, rgba(26, 26, 26, 0.08) 50%, transparent 100%);
  transition: background 0.5s ease;
}

.ft-category-card:hover .ft-category-card__overlay {
  background: linear-gradient(to top, rgba(26, 26, 26, 0.65) 0%, rgba(26, 26, 26, 0.12) 50%, transparent 100%);
}

.ft-category-card__content {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 1.75rem 1.5rem;
  z-index: 2;
}

.ft-category-card__title {
  font-family: 'Cormorant Garamond', serif;
  font-style: italic;
  font-weight: 400;
  font-size: 1.65rem;
  color: #fff;
  letter-spacing: 0.02em;
  line-height: 1.2;
  margin-bottom: 0.35rem;
}

.ft-category-card__subtitle {
  font-family: 'Outfit', sans-serif;
  font-weight: 300;
  font-size: 0.72rem;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.75);
}

.ft-category-card__arrow {
  position: absolute;
  bottom: 1.75rem;
  right: 1.5rem;
  width: 28px;
  height: 28px;
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  transform: translateX(-8px);
  transition: all 0.4s cubic-bezier(0.25, 0.1, 0.25, 1);
  z-index: 2;
}

.ft-category-card:hover .ft-category-card__arrow {
  opacity: 1;
  transform: translateX(0);
}

.ft-category-card__arrow svg {
  width: 18px;
  height: 18px;
  stroke: #fff;
  stroke-width: 1.5;
  fill: none;
}

/* ── FILTER NAV ── */
.ft-filter-nav {
  padding-bottom: 3rem;
}

.ft-filter-nav__heading {
  font-family: 'Cormorant Garamond', serif;
  font-style: italic;
  font-weight: 300;
  font-size: 1.15rem;
  letter-spacing: 0.08em;
  color: #999;
  text-align: center;
  margin-bottom: 1.75rem;
}

.ft-filter-tabs {
  display: flex;
  justify-content: center;
  gap: 0;
  margin-bottom: 0;
  border-bottom: 1px solid #e5e0db;
}

.ft-filter-tab {
  font-family: 'Outfit', sans-serif;
  font-weight: 400;
  font-size: 0.75rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: #999;
  background: none;
  border: none;
  padding: 0.9rem 2.25rem;
  cursor: pointer;
  position: relative;
  transition: color 0.3s ease;
}

.ft-filter-tab::after {
  content: '';
  position: absolute;
  bottom: -1px;
  left: 50%;
  transform: translateX(-50%);
  width: 0;
  height: 1.5px;
  background: #1a1a1a;
  transition: width 0.4s cubic-bezier(0.25, 0.1, 0.25, 1);
}

.ft-filter-tab:hover {
  color: #1a1a1a;
}

.ft-filter-tab:hover::after {
  width: 100%;
}

.ft-filter-tab--active {
  color: #1a1a1a;
}

.ft-filter-tab--active::after {
  width: 100%;
}

/* ── FILTER PANELS ── */
.ft-filter-panel {
  display: none;
  padding: 2.25rem 0 0.5rem;
  animation: ftFadeSlideIn 0.45s cubic-bezier(0.25, 0.1, 0.25, 1);
}

.ft-filter-panel--active {
  display: block;
}

@keyframes ftFadeSlideIn {
  from {
    opacity: 0;
    transform: translateY(-8px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.ft-filter-panel__columns {
  display: flex;
  justify-content: center;
  gap: 4rem;
}

.ft-filter-group {
  min-width: 180px;
}

.ft-filter-group__title {
  font-family: 'Cormorant Garamond', serif;
  font-style: italic;
  font-weight: 400;
  font-size: 1.05rem;
  color: #1a1a1a;
  margin-bottom: 1rem;
  padding-bottom: 0.5rem;
  border-bottom: 1px solid #e5e0db;
}

.ft-filter-group__list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-direction: column;
  gap: 0;
}

.ft-filter-link {
  display: block;
  font-family: 'Outfit', sans-serif;
  font-weight: 300;
  font-size: 0.85rem;
  color: #1a1a1a;
  text-decoration: none;
  padding: 0.5rem 0.75rem;
  margin: 0 -0.75rem;
  border-radius: 2px;
  transition: all 0.25s ease;
  letter-spacing: 0.02em;
}

.ft-filter-link:hover {
  background: #faf8f6;
  color: #1a1a1a;
  padding-left: 1rem;
}

/* ── RESPONSIVE ── */
@media (max-width: 1024px) {
  .ft-category-cards__grid {
    grid-template-columns: repeat(2, 1fr);
    gap: 1rem;
  }

  .ft-filter-panel__columns {
    gap: 2.5rem;
    flex-wrap: wrap;
  }

  .ft-filter-tab {
    padding: 0.8rem 1.5rem;
    font-size: 0.7rem;
  }
}

@media (max-width: 640px) {
  .ft-shop-container {
    padding: 0 1.25rem;
  }

  .ft-category-cards {
    padding: 2rem 0 2rem;
  }

  .ft-category-cards__grid {
    grid-template-columns: repeat(2, 1fr);
    gap: 0.75rem;
  }

  .ft-category-card__title {
    font-size: 1.25rem;
  }

  .ft-category-card__subtitle {
    font-size: 0.65rem;
  }

  .ft-category-card__content {
    padding: 1.25rem 1rem;
  }

  .ft-filter-tabs {
    flex-wrap: wrap;
    justify-content: center;
  }

  .ft-filter-tab {
    padding: 0.7rem 1.25rem;
    font-size: 0.68rem;
  }

  .ft-filter-panel__columns {
    flex-direction: column;
    gap: 1.5rem;
    padding: 1.5rem 0 0.5rem;
  }

  .ft-filter-group {
    min-width: auto;
  }
}

/* ── OUTLET LINK ── */
.ft-outlet-link-wrap {
  text-align: center;
  padding: 0.9rem 0 0.25rem;
}

.ft-outlet-link {
  font-family: 'Outfit', sans-serif;
  font-size: 0.9rem;
