/* ═══════════════════════════════════════
   Frame & Thread — Shop Filter Tabs
   Snippet: Shop Filter JS
   Scope: Frontend only
   Location: Footer
═══════════════════════════════════════ */

document.addEventListener('DOMContentLoaded', function() {
  var tabs = document.querySelectorAll('.ft-filter-tab');
  var panels = document.querySelectorAll('.ft-filter-panel');

  if (!tabs.length) return;

  tabs.forEach(function(tab) {
    tab.addEventListener('click', function() {
      var target = tab.getAttribute('data-tab');
      var isActive = tab.classList.contains('ft-filter-tab--active');

      /* Close all */
      tabs.forEach(function(t) { t.classList.remove('ft-filter-tab--active'); });
      panels.forEach(function(p) { p.classList.remove('ft-filter-panel--active'); });

      /* If it wasn't active, open it */
      if (!isActive) {
        tab.classList.add('ft-filter-tab--active');
        var activePanel = document.querySelector('[data-panel="' + target + '"]');
        if (activePanel) {
          activePanel.classList.add('ft-filter-panel--active');
        }
      }
    });
  });
});

