/**
 * Shop Context — Display Tweaks
 *
 * Consolidates three previously-separate snippets that all
 * gated on "is this a product/shop/archive page":
 *   - Custom dropdown placeholders (was snippet 14)
 *   - Qty +/- buttons (was snippet 15)
 *   - Variation price fallback (was snippet 18)
 *
 * Running them in one `wp` hook removes two redundant
 * is_product()/is_shop() checks per request.
 *
 * Behavior preserved exactly except:
 *   - Qty buttons now have aria-label attributes (a11y improvement)
 *
 * Everything else (including the <p class="price"> wrapper
 * the CSS depends on) is unchanged.
 */

add_action( 'wp', function () {
    if ( ! ft_is_shop_context() ) return;

    // 1) Custom dropdown placeholders per attribute.
    add_filter( 'woocommerce_dropdown_variation_attribute_options_args', 'ft_custom_dropdown_placeholders' );

    // 2) +/- qty buttons (styled by CSS snippet 28).
    add_action( 'woocommerce_before_quantity_input_field', 'ft_qty_minus_btn' );
    add_action( 'woocommerce_after_quantity_input_field',  'ft_qty_plus_btn' );

    // 3) Variation price fallback.
    add_filter( 'woocommerce_available_variation', 'ft_variation_price_fallback', 10, 3 );
} );

function ft_is_shop_context() {
    return is_product() || is_shop() || is_product_category() || is_product_tag() || is_cart();
}

function ft_custom_dropdown_placeholders( $args ) {
    if ( empty( $args['attribute'] ) ) return $args;

    $placeholders = [
        'pa_length'         => 'Select Length & Type',
        'pa_adhesive-color' => 'Select Adhesive Color',
        'pa_brush-color'    => 'Select Brush Color',
        'pa_color'          => 'Select Color & Size',
        'pa_iron-color'     => 'Select Iron Color',
    ];
    if ( isset( $placeholders[ $args['attribute'] ] ) ) {
        $args['show_option_none'] = $placeholders[ $args['attribute'] ];
    }
    return $args;
}

function ft_qty_minus_btn() {
    echo '<button type="button" class="qty-btn minus" aria-label="Decrease quantity">&minus;</button>';
}

function ft_qty_plus_btn() {
    echo '<button type="button" class="qty-btn plus" aria-label="Increase quantity">+</button>';
}

function ft_variation_price_fallback( $variation, $product, $variation_obj ) {
    // Only fill in when Woo itself didn't provide a price_html.
    if ( ! empty( $variation['price_html'] ) ) return $variation;

    $price_html = $variation_obj->get_price_html();
    if ( $price_html ) {
        // Keep the <p class="price"> wrapper — site CSS targets it
        // (e.g. .woocommerce-variation-price .price in snippet 30).
        $variation['price_html'] = '<p class="price">' . $price_html . '</p>';
    }
    return $variation;
}

