/**
 * FT — Single product price shortcode with B2BKing-matching guest gate
 *
 * For logged-in users: emits the native WooCommerce <p class="price">
 * markup (including sale <del>/<ins>) via woocommerce_template_single_price().
 *
 * For logged-out users: emits markup that matches exactly what
 * B2BKing produces on variable products — span.price > span.b2bking_hidden_price_text
 * with a "Log In to View Prices" link to /my-account/. This ensures
 * consistent appearance across simple and variable product templates
 * for guests, and lets existing B2BKing CSS apply to both cases.
 *
 * Why we don't just let B2BKing filter our output: B2BKing's
 * price-hiding hook doesn't consistently fire when
 * woocommerce_template_single_price() is called from a shortcode
 * context, so we reproduce its guest markup directly.
 *
 * Use in Cornerstone with [ft_single_price].
 */
add_shortcode( 'ft_single_price', function () {
    if ( ! is_product() ) return '';

    global $product;
    if ( ! $product ) return '';

    if ( ! is_user_logged_in() ) {
        $my_account_url = esc_url( wc_get_page_permalink( 'myaccount' ) );
        return '<p class="price"><span class="b2bking_hidden_price_text">'
             . '<a href="' . $my_account_url . '">Log In to View Prices</a>'
             . '</span></p>';
    }

    ob_start();
    woocommerce_template_single_price();
    return ob_get_clean();
} );
